"use strict";const tabcontent=document.getElementsByClassName("profile-tab-content"),tablinks=document.getElementsByClassName("profile-tab-link"),pageURL=new URL(window.location.href),windowParams=new URLSearchParams(window.location.search);function changeTab(evt,tabName){windowParams.set("t",tabName.replace("-tab","")),pageURL.search=windowParams.toString(),window.history.replaceState({path:pageURL.href},"",pageURL.href);for(var i=0;i<tabcontent.length;i++)tabcontent[i].style.display="none";for(i=0;i<tablinks.length;i++)tablinks[i].className=tablinks[i].className.replace(" active","");document.getElementById(tabName).style.display="block",evt.currentTarget.className+=" active"}""!=windowParams.get("t")&&["bio","settings","posts"].includes(windowParams.get("t"))?document.getElementById(windowParams.get("t")).click():document.getElementById("bio").click();